import { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import axios from 'axios';

const api = axios.create({ 
  baseURL: 'http://localhost:5000',
  withCredentials: true 
});

function Table() {
  const [tableData, setTableData] = useState([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');
  const [debugInfo, setDebugInfo] = useState({});
  const navigate = useNavigate();

  const fetchTableData = async () => {
    setLoading(true);
    setError('');

    try {
      const response = await api.get('/sings');

      setDebugInfo({
        status: response.status,
        timestamp: new Date().toISOString(),
        dataLength: response.data?.length || 0
      });

      if (response.status === 200) {
        setTableData(Array.isArray(response.data) ? response.data : [response.data]);
      }
    } catch (err) {
      let errorMessage = '';

      if (err.response) {
        errorMessage = err.response.data.message || `Ошибка ${err.response.status}`;
        setDebugInfo(prev => ({
          ...prev,
          errorResponse: err.response.data,
          errorStatus: err.response.status
        }));

        if (err.response.status === 401) {
          setTimeout(() => navigate('/login'), 1500);
        }
      } else if (err.request) {
        errorMessage = 'Нет ответа от сервера';
      } else {
        errorMessage = 'Ошибка при отправке запроса';
      }

      setError(errorMessage);
    } finally {
      setLoading(false);
    }
  };

  const handleLogout = () => {
    document.cookie.split(';').forEach(cookie => {
      const [key] = cookie.trim().split('=');
      if (key) {
        document.cookie = `${key}=; expires=Thu, 01 Jan 1970 00:00:00 UTC; path=/;`;
      }
    });
    navigate('/login');
  };

  const handleBackToLogin = () => {
    navigate('/login');
  };

  useEffect(() => {
    fetchTableData();
  }, []);

  const renderTable = () => {
    if (tableData.length === 0) {
      return <p className="no-data">Нет данных для отображения</p>;
    }

    const headers = Object.keys(tableData[0]);

    return (
      <div className="table-wrapper">
        <table className="data-table">
          <thead>
            <tr>
              {headers.map(header => (
                <th key={header}>{header}</th>
              ))}
            </tr>
          </thead>
          <tbody>
            {tableData.map((row, index) => (
              <tr key={index}>
                {headers.map(header => (
                  <td key={`${index}-${header}`}>
                    {typeof row[header] === 'object' 
                      ? JSON.stringify(row[header]) 
                      : String(row[header])}
                  </td>
                ))}
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    );
  };

  return (
        <div>
            <nav className="navbar navbar-expand-lg navbar-dark bg-dark flex-column align-items-start p-0">
                <div className="container-fluid py-2">
                    <Link className="navbar-brand fs-3 fw-bold" to="/main">roads_admin</Link>
                </div>
                <div className="container-fluid bg-dark py-2">
                    <div className="navbar-nav flex-row">
                        <NavLink className={({ isActive }) => `nav-link me-3 ${isActive ? 'active fw-bold' : ''}`} to="/" end> Главная </NavLink>
                        <NavLink className={({ isActive }) => `nav-link me-3 ${isActive ? 'active fw-bold' : ''}`} to="/roads" end> Дороги </NavLink>
                        <NavLink className={({ isActive }) => `nav-link me-3 ${isActive ? 'active fw-bold' : ''}`} to="/sings" end> Дорожные знаки </NavLink>
                        <NavLink className={({ isActive }) => `nav-link me-3 ${isActive ? 'active fw-bold' : ''}`} to="/roads/sings" end> Знаки на дорогах </NavLink>
                    </div>
                </div>
            </nav>
            <div className="Road">
                <p className="Table-header"><h1>Дорожные знаки</h1></p>

                <div>
                    <BootstrapTable 
                        keyField='id' 
                        data={ data?.items || [] } 
                        columns={ columns }
                    />
                </div>
            </div>
        </div>
  );
}

export default Table;
